float predict(const float* x) {
    float s = 0.000000f;
    for (int i = 0; i < N_TREES; i++) s += traverse_tree(i, x);
    return 1.0f / (1.0f + expf(-s));
}
static inline int predict_class(const float* x) { return predict(x) >= 0.5f; }

#endif /* BONSAI_MODEL_H */
